SELECT COUNT(*) AS completed_investigations
FROM investigations
WHERE investigation_status = 'Completed';

SELECT accident_type, accident_type_description
FROM accident_types
ORDER BY accident_type ASC;

SELECT SUM(landing_accidents) AS total_landing_accidents
FROM landing_accidents
WHERE landing_location = 'Los Angeles International Airport';

SELECT landing_accidents
FROM landing_accidents
WHERE accident_id = 1;

SELECT accident_type
FROM accident_types
WHERE accident_type_code = 'TKO';

SELECT COUNT(*) 
FROM takeoff_accidents
WHERE takeoff_casualties > 40;

SELECT year_id, year, year_start_date
FROM years
ORDER BY year;

SELECT cause, cause_category
FROM accident_causes
WHERE cause_category = 'Human Error';

SELECT approach_accidents
FROM approach_accidents
WHERE accident_id = 1;
